values
(
  'RTF',
  '{"es":"Rol / tarea / formato","en":"Role / Task / Format"}'::jsonb,
  '{"es":"RTF separa quién habla, qué debe hacer y cómo entregar la respuesta. Es la estructura más simple para empezar.","en":"RTF separates who speaks, what to do and how to deliver. It is the easiest structure to start with."}'::jsonb,
  '{"es":["Cuando necesitas respuestas claras y directas.","Cuando el formato final es importante (tabla, lista, JSON).","Cuando quieres evitar ambigüedad al iniciar."],"en":["When you need clear direct answers.","When final format matters (table, list, JSON).","When you want less ambiguity from the start."]}'::jsonb,
  '{"es":"Rol: [rol]\nTarea: [tarea]\nFormato: [formato de salida]","en":"Role: [role]\nTask: [task]\nFormat: [output format]"}'::jsonb,
  '{"es":"Rol: Eres un analista de calidad.\nTarea: Evalúa 5 casos borde de login.\nFormato: Lista numerada con riesgo y prioridad.","en":"Role: You are a QA Analyst.\nTask: Evaluate 5 edge cases for login.\nFormat: Numbered list with risk and priority."}'::jsonb,
  array['Role', 'Task', 'Format']::text[],
  array['role', 'goal', 'output-format', 'context', 'inputs', 'constraints', 'examples']::text[],
  0,
  true
),
(
  'TAO',
  '{"es":"Tarea / acción / salida","en":"Task / Action / Output"}'::jsonb,
  '{"es":"TAO define la tarea, el proceso esperado y la salida exacta. Ayuda a guiar ejecución paso a paso.","en":"TAO defines the objective, expected process and exact output for better execution control."}'::jsonb,
  '{"es":["Cuando quieres que el modelo siga un flujo.","Cuando hay varias acciones intermedias.","Cuando necesitas salida consistente."],"en":["When you need a guided workflow.","When there are multiple intermediate actions.","When output consistency is important."]}'::jsonb,
  '{"es":"Tarea: [meta]\nAcción: [pasos o método]\nSalida: [entregable esperado]","en":"Task: [goal]\nAction: [steps/method]\nOutput: [deliverable]"}'::jsonb,
  '{"es":"Tarea: Crear plan de refactor.\nAcción: Analiza módulos e identifica deuda técnica.\nSalida: Tabla con impacto, esfuerzo y orden sugerido.","en":"Task: Create refactor plan.\nAction: Analyze modules, detect debt, prioritize.\nOutput: Table with impact, effort and suggested order."}'::jsonb,
  array['Task', 'Action', 'Output']::text[],
  array['goal', 'constraints', 'output-format', 'context', 'inputs', 'examples', 'role']::text[],
  1,
  true
),
(
  'BAB',
  '{"es":"Antes / después / puente","en":"Before / After / Bridge"}'::jsonb,
  '{"es":"BAB contrasta estado actual y estado deseado, luego construye el puente para llegar.","en":"BAB compares current vs desired state and defines the bridge to get there."}'::jsonb,
  '{"es":["Para contenido de transformación (marketing, mejora).","Cuando explicas cambios de proceso.","Para propuestas orientadas a valor."],"en":["For transformation messaging.","When explaining process changes.","For value-driven proposals."]}'::jsonb,
  '{"es":"Antes: [situación actual]\nDespués: [resultado ideal]\nPuente: [acciones para pasar de A a B]","en":"Before: [current state]\nAfter: [desired state]\nBridge: [actions from A to B]"}'::jsonb,
  '{"es":"Antes: El equipo tarda 3 días en documentar tickets.\nDespués: Tickets claros en menos de 30 min.\nPuente: Plantilla fija, checklist y revisión rápida.","en":"Before: Team needs 3 days to document tickets.\nAfter: Clear tickets in under 30 min.\nBridge: Fixed template, checklist and quick review."}'::jsonb,
  array['Before', 'After', 'Bridge']::text[],
  array['context', 'goal', 'constraints', 'output-format', 'examples', 'role', 'inputs']::text[],
  2,
  true
),
(
  'CARE',
  '{"es":"Contexto / acción / resultado / ejemplos","en":"Context / Action / Result / Examples"}'::jsonb,
  '{"es":"CARE añade ejemplos para estabilizar estilo y calidad del resultado.","en":"CARE adds examples to stabilize quality and style of the output."}'::jsonb,
  '{"es":["Cuando el contexto es complejo.","Cuando necesitas respuestas reproducibles.","Cuando quieres enseñar con ejemplos."],"en":["When context is complex.","When you need repeatable responses.","When you want example-driven guidance."]}'::jsonb,
  '{"es":"Contexto: [contexto]\nAcción: [qué hacer]\nResultado: [resultado esperado]\nEjemplos: [ejemplos de referencia]","en":"Context: [context]\nAction: [what to do]\nResult: [expected result]\nExamples: [references]"}'::jsonb,
  '{"es":"Contexto: Lanzamiento de curso online.\nAcción: Crea 3 copys para landing.\nResultado: Copy persuasivo por segmento.\nEjemplos: CTA fuerte y máximo 80 palabras.","en":"Context: Online course launch.\nAction: Create 3 landing page copies.\nResult: Persuasive copy by segment.\nExamples: Clear style, strong CTA, max 80 words."}'::jsonb,
  array['Context', 'Action', 'Result', 'Examples']::text[],
  array['context', 'constraints', 'goal', 'examples', 'output-format', 'inputs', 'role']::text[],
  3,
  true
),
(
  'CO-STAR',
  '{"es":"Contexto / objetivo / estilo / tono / audiencia / respuesta","en":"Context / Objective / Style / Tone / Audience / Response"}'::jsonb,
  '{"es":"CO-STAR controla intención y voz del mensaje con mucha precisión para públicos distintos.","en":"CO-STAR gives tight control over intention and voice across audiences."}'::jsonb,
  '{"es":["Para copywriting y comunicación.","Cuando importa tono y audiencia.","Para briefs creativos multi-formato."],"en":["For copywriting and communication.","When tone and audience matter.","For creative multi-format briefs."]}'::jsonb,
  '{"es":"Contexto: [situación]\nObjetivo: [objetivo]\nEstilo: [estilo]\nTono: [tono]\nAudiencia: [público]\nRespuesta: [tipo de respuesta]","en":"Context: [situation]\nObjective: [objective]\nStyle: [style]\nTone: [tone]\nAudience: [audience]\nResponse: [response type]"}'::jsonb,
  '{"es":"Contexto: Lanzamiento de app fitness.\nObjetivo: Aumentar registros.\nEstilo: Directo y útil.\nTono: Motivador.\nAudiencia: Personas ocupadas de 25-40.\nRespuesta: 5 anuncios cortos.","en":"Context: Fitness app launch.\nObjective: Increase signups.\nStyle: Direct and useful.\nTone: Motivational.\nAudience: Busy people 25-40.\nResponse: 5 short ads."}'::jsonb,
  array['Context', 'Objective', 'Style', 'Tone', 'Audience', 'Response']::text[],
