),
(
  'CRISPE',
  '{"es":"Capacidad / rol / insight / declaración / personalidad / experimento","en":"Capacity / Role / Insight / Statement / Personality / Experiment"}'::jsonb,
  '{"es":"CRISPE es útil para tareas creativas o estratégicas donde quieres una personalidad y experimentación explícita.","en":"CRISPE is useful for strategic or creative work where personality and experimentation are explicit."}'::jsonb,
  '{"es":["Para brainstorming avanzado.","Cuando quieres hipótesis y experimentos.","Para outputs con identidad de marca."],"en":["For advanced brainstorming.","When you need hypotheses and experiments.","For brand-voice outputs."]}'::jsonb,
  '{"es":"Capacidad: [capacidades]\nRol: [rol]\nInsight: [dato clave]\nDeclaración: [objetivo o tesis]\nPersonalidad: [estilo de voz]\nExperimento: [prueba o variaciones]","en":"Capacity: [capabilities]\nRole: [role]\nInsight: [key data]\nStatement: [thesis/goal]\nPersonality: [voice style]\nExperiment: [test/variations]"}'::jsonb,
  '{"es":"Capacidad: Estratega de growth.\nRol: Consultor senior.\nInsight: CTR cayó 18%.\nDeclaración: Recuperar CTR en 14 días.\nPersonalidad: Práctico y directo.\nExperimento: 3 variantes de asunto + CTA.","en":"Capacity: Growth strategist.\nRole: Senior consultant.\nInsight: CTR dropped 18%.\nStatement: Recover CTR in 14 days.\nPersonality: Practical and concise.\nExperiment: 3 subject line + CTA variants."}'::jsonb,
  array['Capacity', 'Role', 'Insight', 'Statement', 'Personality', 'Experiment']::text[],
