  '{"es":"Situación: [situación]\nTarea: [tarea]\nAcción: [acción tomada]\nResultado: [resultado medible]","en":"Situation: [situation]\nTask: [task]\nAction: [action]\nResult: [measurable result]"}'::jsonb,
